 16→class DailyReportAiEmailController extends Controller
 17→{
 18→    // 智能日报邮件功能仅限指定用户（线上 171514，测试 232753）
 19→    private const AI_EMAIL_ALLOWED_IDS = [171514];
 20→    public function taskList(Request $request): JsonResponse
 21→    {
 22→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
 23→        if (!$this->inWhitelist($sfuserId)) {
 24→            return $this->responseJsonFail('无权限');
 25→        }
 26→
 27→        $list = DB::table('daily_report_ai_email_tasks')
 28→            ->where('sfuser_id', $sfuserId)
 29→            ->whereNull('deleted_at')
 30→            ->orderByDesc('created_at')
 31→            ->get(['id', 'name', 'dimension', 'report_range', 'send_cycle', 'send_day', 'send_time', 'system_prompt', 'is_on', 'created_at']);
 32→
 33→        return $this->responseJsonSuccess(['list' => $list]);
 34→    }
 35→
 36→    public function taskCreate(Request $request): JsonResponse
 37→    {
 38→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
 39→        if (!$this->inWhitelist($sfuserId)) {
 40→            return $this->responseJsonFail('无权限');
 41→        }
 42→
 43→        $input = Arr::only($request->all(), ['name', 'dimension', 'report_range', 'send_cycle', 'send_day', 'send_time', 'system_prompt']);
 44→
 45→        $id = DB::table('daily_report_ai_email_tasks')->insertGetId([
 46→            'sfuser_id' => $sfuserId,
 47→            'name' => $input['name'],
 48→            'dimension' => $input['dimension'] ?? 'department',
 49→            'report_range' => $input['report_range'] ?? 'today',
 50→            'send_cycle' => $input['send_cycle'] ?? 'daily',
 51→            'send_day' => $input['send_day'] ?? 1,
 52→            'send_time' => $input['send_time'] ?? '09:00',
 53→            'system_prompt' => $input['system_prompt'] ?? '',
 54→            'is_on' => 1,
 55→            'created_at' => now(),
 56→            'updated_at' => now(),
 57→        ]);
 58→
 59→        \Log::info('[lbl][0416-AI日报][AiEmail][CREATE] 创建邮件任务', ['sfuser_id' => $sfuserId, 'task_id' => $id, 'name' => $input['name']]);
 60→
 61→        return $this->responseJsonSuccess(['id' => $id]);
 62→    }
 63→
 64→    public function taskUpdate(Request $request): JsonResponse
 65→    {
 66→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
 67→        if (!$this->inWhitelist($sfuserId)) {
 68→            return $this->responseJsonFail('无权限');
 69→        }
 70→
 71→        $id = $request->input('id');
 72→        $input = Arr::only($request->all(), ['name', 'dimension', 'report_range', 'send_cycle', 'send_day', 'send_time', 'system_prompt']);
 73→
 74→        $affected = DB::table('daily_report_ai_email_tasks')
 75→            ->where('id', $id)
 76→            ->where('sfuser_id', $sfuserId)
 77→            ->whereNull('deleted_at')
 78→            ->update(array_merge(
 79→                array_filter($input, fn ($v) => $v !== null),
