 83→        \Log::info('[lbl][0416-AI日报][AiEmail][UPDATE] 更新邮件任务', ['sfuser_id' => $sfuserId, 'task_id' => $id, 'affected' => $affected]);
 84→
 85→        return $this->responseJsonSuccess(['affected' => $affected]);
 86→    }
 87→
 88→    public function taskDelete(Request $request): JsonResponse
 89→    {
 90→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
 91→        if (!$this->inWhitelist($sfuserId)) {
 92→            return $this->responseJsonFail('无权限');
