106→
107→    public function taskToggle(Request $request): JsonResponse
108→    {
109→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
110→        if (!$this->inWhitelist($sfuserId)) {
111→            return $this->responseJsonFail('无权限');
