214→async function extractSlots(params: {
215→    message: string
216→    conversation_id?: string
217→    has_existing_context?: boolean
218→    available_groups?: string[]
219→    available_members?: string[]
220→    previous_context?: { member_type: string; members: string[]; period_start: string; period_end: string }
221→}): Promise<ExtractSlotsResult | null> {
222→    try {
223→        const res = await axiosPostWithInt(BASE + 'daily-report/ai/extract-slots', handlerParams(params))
224→        // oa-server 返回 { message, ai_analysis_config }，oa-core TransferRequestService 做 blocking AI，结果在 ai_result
225→        const aiResult = res.data?.ai_result ?? ''
226→        if (!aiResult) {
227→            return null
228→        }
229→        return parseSlotJson(aiResult)
230→    } catch (e) {
231→        Message.error(e?.error_msg || '意图识别失败')
232→        return null
233→    }
234→}
