import { Message } from 'element-ui'
import { difference } from 'lodash'

import { axiosPostWithInt } from '@/apis/axiosInstance'
import { ajaxUrl } from '../../appConstant'

const BASE = ajaxUrl.UserAPI

function handlerParams(params: Record<string, any>): Record<string, any> {
    const intact_columns = difference(Object.keys(params), [
        'decrypt_config',
        'hash_filter',
        'page',
        'per_page',
        'sys_lang',
    ])
    return { ...params, intact_columns, sys_site: 'CHN' }
}

// ----------------------------------------------------------------
// 角色
// ----------------------------------------------------------------

export interface AiRole {
    id: number
    name: string
    system_prompt: string
    created_at: string
}

async function getRoleList(): Promise<AiRole[]> {
    try {
        const res = await axiosPostWithInt(BASE + 'daily-report/ai/role/list', handlerParams({}))
        return res.data?.list ?? []
    } catch (e) {
        Message.error(e?.error_msg)
        return []
    }
}

async function createRole(params: { name: string; system_prompt: string }): Promise<number | null> {
    try {
        console.info('[lbl][0416-AI日报][AiRole][CREATE] 创建角色', { name: params.name })
        const res = await axiosPostWithInt(BASE + 'daily-report/ai/role/create', handlerParams(params))
        return res.data?.id ?? null
    } catch (e) {
        Message.error(e?.error_msg)
        return null
    }
}

async function updateRole(params: { id: number; name?: string; system_prompt?: string }): Promise<void> {
    try {
        console.info('[lbl][0416-AI日报][AiRole][UPDATE] 更新角色', { id: params.id })
        await axiosPostWithInt(BASE + 'daily-report/ai/role/update', handlerParams(params))
    } catch (e) {
        Message.error(e?.error_msg)
    }
}

async function deleteRole(id: number): Promise<void> {
    try {
        console.info('[lbl][0416-AI日报][AiRole][DELETE] 删除角色', { id })
        await axiosPostWithInt(BASE + 'daily-report/ai/role/delete', handlerParams({ id }))
    } catch (e) {
        Message.error(e?.error_msg)
    }
}

// ----------------------------------------------------------------
// 常用提示词
// ----------------------------------------------------------------

export interface AiPrompt {
    id: number
    content: string
    sort: number
}

async function getPromptList(): Promise<AiPrompt[]> {
    try {
        const res = await axiosPostWithInt(BASE + 'daily-report/ai/prompt/list', handlerParams({}))
        return res.data?.list ?? []
    } catch (e) {
        Message.error(e?.error_msg)
        return []
    }
}

async function createPrompt(content: string): Promise<number | null> {
    try {
        console.info('[lbl][0416-AI日报][AiPrompt][CREATE] 创建提示词')
        const res = await axiosPostWithInt(BASE + 'daily-report/ai/prompt/create', handlerParams({ content }))
        return res.data?.id ?? null
    } catch (e) {
        Message.error(e?.error_msg)
        return null
    }
}

async function deletePrompt(id: number): Promise<void> {
    try {
        console.info('[lbl][0416-AI日报][AiPrompt][DELETE] 删除提示词', { id })
        await axiosPostWithInt(BASE + 'daily-report/ai/prompt/delete', handlerParams({ id }))
    } catch (e) {
        Message.error(e?.error_msg)
    }
}

// ----------------------------------------------------------------
// 历史会话
// ----------------------------------------------------------------

export interface AiSession {
    id: number
    title: string
    updated_at: string
}

async function getSessionList(roleId: number): Promise<AiSession[]> {
    try {
        const res = await axiosPostWithInt(BASE + 'daily-report/ai/session/list', handlerParams({ role_id: roleId }))
        return res.data?.list ?? []
    } catch (e) {
        Message.error(e?.error_msg)
        return []
    }
}

export interface AiMessage {
    id: number
    role: 'user' | 'assistant' | 'context'
    content: string
    created_at: string
    is_truncated?: boolean
    full_length?: number
}

async function getSessionMessages(sessionId: number): Promise<AiMessage[]> {
    try {
        const res = await axiosPostWithInt(BASE + 'daily-report/ai/session/messages', handlerParams({ session_id: sessionId }))
        return res.data?.list ?? []
    } catch (e) {
        Message.error(e?.error_msg)
        return []
    }
}

async function getContextMore(messageId: number, offset: number): Promise<{ content: string; has_more: boolean; full_length: number } | null> {
    try {
        const res = await axiosPostWithInt(BASE + 'daily-report/ai/session/context-more', handlerParams({ message_id: messageId, offset }))
        return res.data ?? null
    } catch (e) {
        Message.error(e?.error_msg)
        return null
    }
}

// ----------------------------------------------------------------
// 意图识别：提取查询槽位
// ----------------------------------------------------------------

export interface ExtractSlotsResult {
    intent: 'analyze' | 'new_query'
    slots_complete: boolean
    member_type: 'group' | 'individual'
    members: string[]
    period_start: string
    period_end: string
    period_raw: string
    reply: string
    conversation_id: string
}

/**
 * 从 AI 原始文本中解析槽位 JSON，兼容 markdown 代码块包裹
 */
function parseSlotJson(text: string): ExtractSlotsResult {
    const fallback: ExtractSlotsResult = {
        intent: 'new_query',
        slots_complete: false,
        members: [],
        member_type: 'individual',
        period_start: '',
        period_end: '',
        period_raw: '',
        reply: '抱歉没理解你的意思，请告诉我你想查哪个分组或具体成员的日报，以及查哪个时间段？',
        conversation_id: '',
    }
    const match = text.match(/\{[\s\S]*\}/)
    if (!match) {
        console.warn('[AiSlots] no JSON found in answer', text.slice(0, 500))
        return fallback
    }
    try {
        const data = JSON.parse(match[0])
        return {
            intent: data.intent ?? 'new_query',
            slots_complete: !!data.slots_complete,
            members: data.members ?? [],
            member_type: data.member_type ?? '',
            period_start: data.period_start ?? '',
            period_end: data.period_end ?? '',
            period_raw: data.period_raw ?? '',
            reply: data.reply ?? '',
            conversation_id: '',
        }
    } catch {
        console.warn('[AiSlots] JSON parse failed', match[0].slice(0, 500))
        return fallback
    }
}

async function extractSlots(params: {
    message: string
    conversation_id?: string
    has_existing_context?: boolean
    available_groups?: string[]
    available_members?: string[]
    previous_context?: { member_type: string; members: string[]; period_start: string; period_end: string }
}): Promise<ExtractSlotsResult | null> {
    try {
        const res = await axiosPostWithInt(BASE + 'daily-report/ai/extract-slots', handlerParams(params))
        // oa-server 返回 { message, ai_analysis_config }，oa-core TransferRequestService 做 blocking AI，结果在 ai_result
        const aiResult = res.data?.ai_result ?? ''
        if (!aiResult) {
            return null
        }
        return parseSlotJson(aiResult)
    } catch (e) {
        Message.error(e?.error_msg || '意图识别失败')
        return null
    }
}

// ----------------------------------------------------------------
// 保存消息（意图识别阶段的对话落库）
// ----------------------------------------------------------------

async function saveMessages(params: {
    role_id: number
    session_id?: number | null
    messages: { role: string; content: string }[]
}): Promise<number | null> {
    try {
        const res = await axiosPostWithInt(BASE + 'daily-report/ai/save-messages', handlerParams(params as Record<string, any>))
        return res.data?.session_id ?? null
    } catch (e) {
        return null
    }
}

// ----------------------------------------------------------------
// 发送消息（SSE 流式）
// 返回 EventSource 风格的 ReadableStream，调用方自行消费
// ----------------------------------------------------------------

export interface AskParams {
    role_id: number
    session_id?: number | null
    message: string
    report_context?: string
    report_context_raw?: string
    history?: { role: 'user' | 'assistant'; content: string }[]
    system_prompt?: string
}

// ----------------------------------------------------------------
// 权限检查
// ----------------------------------------------------------------

async function checkAccess(): Promise<boolean> {
    try {
        const res = await axiosPostWithInt(BASE + 'daily-report/ai/check-access', handlerParams({}))
        return res.data?.has_access ?? false
    } catch (e) {
        return false
    }
}

async function checkGroupAccess(): Promise<boolean> {
    try {
        const res = await axiosPostWithInt(BASE + 'daily-report/ai/check-group-access', handlerParams({}))
        return res.data?.has_access ?? false
    } catch (e) {
        return false
    }
}

/**
 * 发送消息，返回 fetch Response（SSE）
 * 调用方通过 response.body.getReader() 读取流
 */
async function askAi(params: AskParams, signal?: AbortSignal): Promise<Response> {
    const url = BASE + 'daily-report/ai/ask'
    const headers: Record<string, string> = {
        'Content-Type': 'application/json',
    }
    const axiosDefaults = (axiosPostWithInt as any)?.defaults?.headers?.common ?? {}
    Object.assign(headers, axiosDefaults)

    // AI streaming 由 oa-core TransferRequestService 完成，通过 ai_analysis_config 参数控制
    const { system_prompt, history, ...restParams } = params
    const payload: Record<string, any> = {
        ...restParams,
        response_format: 'stream',
        ai_analysis_config: {
            system_prompt: system_prompt || '',
            target_field: 'query',
            history: history || [],
        },
    }

    return fetch(url, {
        method: 'POST',
        headers,
        credentials: 'include',
        signal,
        body: JSON.stringify(handlerParams(payload)),
    })
}

// ----------------------------------------------------------------
// AI 邮件任务
// ----------------------------------------------------------------

export interface AiEmailTask {
    id: number
    name: string
    dimension: string
    report_range: string
    send_cycle: string
    send_day: number
    send_time: string
    system_prompt: string
    is_on: number
    created_at: string
}

async function getEmailTaskList(): Promise<AiEmailTask[]> {
    try {
        const res = await axiosPostWithInt(BASE + 'daily-report/ai-email/task/list', handlerParams({}))
        return res.data?.list ?? []
    } catch (e) {
        Message.error(e?.error_msg)
        return []
    }
}

async function createEmailTask(params: {
    name: string
    system_prompt: string
    dimension?: string
    report_range?: string
    send_cycle?: string
    send_day?: number
    send_time?: string
}): Promise<number | null> {
    try {
        console.info('[lbl][0416-AI日报][AiEmail][CREATE] 创建邮件任务', { name: params.name })
        const res = await axiosPostWithInt(BASE + 'daily-report/ai-email/task/create', handlerParams(params))
        return res.data?.id ?? null
    } catch (e) {
        Message.error(e?.error_msg)
        return null
    }
}

async function updateEmailTask(params: {
    id: number
    name?: string
    system_prompt?: string
    dimension?: string
    report_range?: string
    send_cycle?: string
    send_day?: number
    send_time?: string
}): Promise<void> {
    try {
        console.info('[lbl][0416-AI日报][AiEmail][UPDATE] 更新邮件任务', { id: params.id })
        await axiosPostWithInt(BASE + 'daily-report/ai-email/task/update', handlerParams(params))
    } catch (e) {
        Message.error(e?.error_msg)
    }
}

async function deleteEmailTask(id: number): Promise<void> {
    try {
        console.info('[lbl][0416-AI日报][AiEmail][DELETE] 删除邮件任务', { id })
        await axiosPostWithInt(BASE + 'daily-report/ai-email/task/delete', handlerParams({ id }))
    } catch (e) {
        Message.error(e?.error_msg)
    }
}

async function toggleEmailTask(id: number, isOn: number): Promise<void> {
    try {
        console.info('[lbl][0416-AI日报][AiEmail][UPDATE] 切换邮件任务开关', { id, isOn })
        await axiosPostWithInt(BASE + 'daily-report/ai-email/task/toggle', handlerParams({ id, is_on: isOn }))
    } catch (e) {
        Message.error(e?.error_msg)
    }
}

async function triggerEmailTask(id: number): Promise<boolean> {
    try {
        console.info('[lbl][0416-AI日报][AiEmail][TRIGGER] 手动触发邮件任务', { id })
        await axiosPostWithInt(BASE + 'daily-report/ai-email/task/trigger', handlerParams({ id }))
        return true
    } catch (e) {
        Message.error(e?.error_msg || '触发失败')
        return false
    }
}

/**
 * 测试 Prompt 效果，返回 fetch Response（SSE）
 */
async function testEmailTask(params: {
    system_prompt: string
    dimension: string
    report_range: string
    group_key: string
}, signal?: AbortSignal): Promise<Response> {
    const url = BASE + 'daily-report/ai-email/task/test'
    const headers: Record<string, string> = { 'Content-Type': 'application/json' }
    const axiosDefaults = (axiosPostWithInt as any)?.defaults?.headers?.common ?? {}
    Object.assign(headers, axiosDefaults)

    // AI streaming + 解密 + 压缩由 oa-core TransferRequestService 完成
    // 前端发送 minimal ai_analysis_config 触发 AI streaming path，target_field/compress/decrypt_config 由 oa-server 响应合并
    return fetch(url, {
        method: 'POST',
        headers,
        credentials: 'include',
        signal,
        body: JSON.stringify(handlerParams({
            ...params,
            response_format: 'stream',
            ai_analysis_config: {
                system_prompt: params.system_prompt,
            },
        } as Record<string, any>)),
    })
}

export default {
    checkAccess,
    checkGroupAccess,
    getRoleList,
    createRole,
    updateRole,
    deleteRole,
    getPromptList,
    createPrompt,
    deletePrompt,
    getSessionList,
    getSessionMessages,
    getContextMore,
    askAi,
    extractSlots,
    saveMessages,
    getEmailTaskList,
    createEmailTask,
    updateEmailTask,
    deleteEmailTask,
    toggleEmailTask,
    triggerEmailTask,
    testEmailTask,
}

