]);

if (!array_key_exists($input['type'], OaSetting::OA_SETTING_MAP)) {
    return $this->responseJsonFail('wrong type given', CommonException::ERR_COMMON_INVALID_ARGUMENTS);
}
$updateColumns = [
    'type' => $input['type'],
    'creator_id' => Auth::id(),
    'is_on' => Arr::get($input, 'is_on', 1) === 0 ? 0 : 1, // 只有设置为 0 才表示关闭，否则都是开启状态
];

// 传递了 sfuser_ids, 我们才处理 nicknames, 否则我们不处理
if (Arr::exists($input, 'sfuser_ids')) {
    $updateColumns['ids'] = Arr::get($input, 'sfuser_ids', []);
    $updateColumns['nicknames'] = Arr::get($input, 'nicknames_plaintext', []);
}

// 针对特殊配置，如果传递了，需要判断部门是否重复
if (Arr::has($input, 'special_config')) {
    $specialConfig = Arr::get($input, 'special_config');
    if ($specialConfig) {
        $departmentIds = Arr::flatten(data_get($specialConfig, '*.department_ids', []));
        if (count($departmentIds) != count(array_unique($departmentIds))) {
            // 数目不一致，表示存在重复的部门 ID
            return $this->responseJsonFail(__('my_api.repeat_department_id'), CommonException::ERR_COMMON_INVALID_ARGUMENTS);
        }

        $updateColumns['special_config'] = array_map(function ($item) {
            return [
                'department_ids' => $item['department_ids'],
                'ids' => $item['sfuser_ids'],
                'nicknames' => $item['nicknames_plaintext'],
            ];
        }, $specialConfig);
    } else {
        // 传递空的配置项的时候，将原有的置为空
        $updateColumns['special_config'] = [];
    }
}
// 保存前先取旧的 ids，用于 diff 出新增用户
$oldIds = [];
if ($input['type'] === 'daily_report_ai' && Arr::exists($input, 'sfuser_ids')) {
    $existing = OaSetting::where('type', 'daily_report_ai')->select('ids')->first();
    $oldIds = $existing ? ($existing->ids ?? []) : [];

