// ----------------------------------------------------------------

export interface AiEmailTask {
    id: number
    name: string
    dimension: string
    report_range: string
    send_cycle: string
    send_day: number
    send_time: string
    system_prompt: string
    is_on: number
    created_at: string
}

async function getEmailTaskList(): Promise<AiEmailTask[]> {
    try {
        const res = await axiosPostWithInt(BASE + 'daily-report/ai-email/task/list', handlerParams({}))
        return res.data?.list ?? []
    } catch (e) {
        Message.error(e?.error_msg)
        return []
    }
}

async function createEmailTask(params: {
    name: string
    system_prompt: string
    dimension?: string
    report_range?: string
    send_cycle?: string
    send_day?: number
    send_time?: string
}): Promise<number | null> {
    try {
        console.info('[lbl][0416-AI日报][AiEmail][CREATE] 创建邮件任务', { name: params.name })
        const res = await axiosPostWithInt(BASE + 'daily-report/ai-email/task/create', handlerParams(params))
        return res.data?.id ?? null
    } catch (e) {
        Message.error(e?.error_msg)
        return null
    }
}

async function updateEmailTask(params: {
    id: number
    name?: string
    system_prompt?: string
    dimension?: string
    report_range?: string
    send_cycle?: string
    send_day?: number
    send_time?: string
}): Promise<void> {
    try {
        console.info('[lbl][0416-AI日报][AiEmail][UPDATE] 更新邮件任务', { id: params.id })
        await axiosPostWithInt(BASE + 'daily-report/ai-email/task/update', handlerParams(params))
    } catch (e) {
        Message.error(e?.error_msg)
    }
}

async function deleteEmailTask(id: number): Promise<void> {
    try {
        console.info('[lbl][0416-AI日报][AiEmail][DELETE] 删除邮件任务', { id })
        await axiosPostWithInt(BASE + 'daily-report/ai-email/task/delete', handlerParams({ id }))
    } catch (e) {
        Message.error(e?.error_msg)
    }
}

async function toggleEmailTask(id: number, isOn: number): Promise<void> {
    try {
        console.info('[lbl][0416-AI日报][AiEmail][UPDATE] 切换邮件任务开关', { id, isOn })
        await axiosPostWithInt(BASE + 'daily-report/ai-email/task/toggle', handlerParams({ id, is_on: isOn }))
    } catch (e) {
        Message.error(e?.error_msg)
    }
}

async function triggerEmailTask(id: number): Promise<boolean> {
    try {
        console.info('[lbl][0416-AI日报][AiEmail][TRIGGER] 手动触发邮件任务', { id })
        await axiosPostWithInt(BASE + 'daily-report/ai-email/task/trigger', handlerParams({ id }))
        return true
    } catch (e) {
        Message.error(e?.error_msg || '触发失败')
        return false
    }
}

/**
 * 测试 Prompt 效果，返回 fetch Response（SSE）
 */
async function testEmailTask(params: {
    system_prompt: string
    dimension: string
    report_range: string
    group_key: string
}, signal?: AbortSignal): Promise<Response> {
    const url = BASE + 'daily-report/ai-email/task/test'
    const headers: Record<string, string> = { 'Content-Type': 'application/json' }
    const axiosDefaults = (axiosPostWithInt as any)?.defaults?.headers?.common ?? {}
    Object.assign(headers, axiosDefaults)

    // AI streaming + 解密 + 压缩由 oa-core TransferRequestService 完成
    // 前端发送 minimal ai_analysis_config 触发 AI streaming path，target_field/compress/decrypt_config 由 oa-server 响应合并
    return fetch(url, {
        method: 'POST',
        headers,
        credentials: 'include',
        signal,
        body: JSON.stringify(handlerParams({
            ...params,
            response_format: 'stream',
            ai_analysis_config: {
                system_prompt: params.system_prompt,
            },
        } as Record<string, any>)),
    })
}

export default {
    checkAccess,
    checkGroupAccess,
    getRoleList,
    createRole,
    updateRole,
    deleteRole,
    getPromptList,
    createPrompt,
    deletePrompt,
    getSessionList,
    getSessionMessages,
    getContextMore,
    askAi,
    extractSlots,
    saveMessages,
    getEmailTaskList,
    createEmailTask,
    updateEmailTask,
    deleteEmailTask,
    toggleEmailTask,
    triggerEmailTask,
    testEmailTask,
}

