 46→    public function handle(): bool
 47→    {
 48→        // 工作日判断
 49→        $today = now()->toDateString();
 50→        $todayCalendar = ShiftCalendar::where('full_date', $today)->first();
 51→        if (!$todayCalendar || $todayCalendar->is_weekend || $todayCalendar->is_holiday) {
 52→            info('[lbl][0422-AI日报邮件][AiEmailJob] 非工作日，跳过');
 53→            return true;
 54→        }
 55→
 56→        // 获取收件人：白名单 + 固定额外收件人
 57→        $recipientIds = $this->getRecipientIds();
 58→        if (empty($recipientIds)) {
 59→            info('[lbl][0422-AI日报邮件][AiEmailJob] 无收件人，跳过');
 60→            return true;
 61→        }
 62→
 63→        info('[lbl][0422-AI日报邮件][AiEmailJob] 开始处理', [
 64→            'date' => $today,
 65→            'recipient_count' => count($recipientIds),
 66→            'recipient_ids' => $recipientIds,
 67→        ]);
 68→
 69→        // 获取上个工作日
 70→        $lastWorkday = ShiftCalendar::where('is_weekend', 0)
 71→            ->where('is_holiday', 0)
 72→            ->where('full_date', '<', $today)
 73→            ->orderByDesc('full_date')
 74→            ->value('full_date');
 75→
 76→        if (!$lastWorkday) {
 77→            info('[lbl][0422-AI日报邮件][AiEmailJob] 找不到上个工作日，跳过');
 78→            return true;
 79→        }
 80→
 81→        $processedCount = 0;
 82→        $totalRecipients = count($recipientIds);
 83→
 84→        foreach ($recipientIds as $sfuserId) {
 85→            try {
 86→                $this->processRecipient($sfuserId, $lastWorkday);
 87→                ++$processedCount;
 88→            } catch (\Throwable $e) {
 89→                info("[lbl][0422-AI日报邮件][AiEmailJob] sfuser={$sfuserId} 处理失败: {$e->getMessage()}", [
 90→                    'trace' => mb_substr($e->getTraceAsString(), 0, 500),
 91→                ]);
 92→            }
 93→
 94→            // 间隔 65 秒，避免打满 Vertex AI TPM 配额
 95→            if ($processedCount < $totalRecipients) {
 96→                info("[lbl][0422-AI日报邮件][AiEmailJob] 等待 65s 处理下一个收件人");
 97→                sleep(65);
 98→            }
 99→        }
100→
101→        info('[lbl][0422-AI日报邮件][AiEmailJob] 全部完成', [
