111→     */
112→    private function getRecipientIds(): array
113→    {
114→        $setting = OaSetting::where('type', 'daily_report_ai')->select('ids', 'is_on')->first();
115→        $whitelistIds = ($setting && $setting->is_on) ? ($setting->ids ?? []) : [];
116→
