120→    /**
121→     * 处理单个收件人：查直属下属日报 → 组装邮件 → 发送.
122→     */
123→    private function processRecipient(int $sfuserId, string $reportDate): void
124→    {
125→        // 读取邮箱配置
126→        $mc = MailConfig::where('type', "daily_report_{$sfuserId}")->first();
127→        if (!$mc || empty(Arr::get($mc->config, 'to_email'))) {
128→            info("[lbl][0422-AI日报邮件][AiEmailJob] sfuser={$sfuserId} 无邮箱配置，跳过");
129→            return;
130→        }
131→
132→        $toEmails = Arr::get($mc->config, 'to_email');
133→        $sfuserToken = Arr::get($mc->config, 'sfuser_authorized_token', '');
134→        if (!$sfuserToken) {
135→            info("[lbl][0422-AI日报邮件][AiEmailJob] sfuser={$sfuserId} 无 token，跳过");
136→            return;
137→        }
138→
139→        // 查询直属下属（direct_supervisor_id = 当前收件人）
140→        $subordinateIds = Sfuser::where('direct_supervisor_id', $sfuserId)
141→            ->where('status', 1)
142→            ->pluck('id')
143→            ->toArray();
144→
145→        if (empty($subordinateIds)) {
146→            info("[lbl][0422-AI日报邮件][AiEmailJob] sfuser={$sfuserId} 无直属下属，跳过");
147→            return;
148→        }
149→
150→        // 拉取日报数据
151→        $dailyService = app(DailyReportService::class);
152→        $data = $dailyService->getOthersDailyReportListEnable(
153→            $reportDate,
154→            $reportDate,
155→            $sfuserId,
156→            $subordinateIds,
157→            10000
158→        );
159→
160→        if (empty($data['reports']['report_list'])) {
161→            info("[lbl][0422-AI日报邮件][AiEmailJob] sfuser={$sfuserId} 日期={$reportDate} 无日报数据，跳过");
162→            return;
163→        }
164→
165→        $reportList = $data['reports']['report_list'];
166→
167→        // 组装邮件内容
168→        $content = '';
169→        $no = 0;
170→        foreach ($reportList as $report) {
171→            $nickname = $report['data']['nickname'] ?? '';
172→            if (empty($nickname)) {
173→                continue;
174→            }
175→            $nickname = EncryptService::app()->markEncrString(e($nickname));
176→            $reportContent = EncryptService::app()->markEncrString($report['content']);
177→            ++$no;
178→            $content .= '<p><b>'.$no.'、 '.$nickname.'</b></p>';
179→            $content .= '<div style="border:1px solid #eee;padding:8px;margin-bottom:12px;">'.$reportContent.'</div>';
180→        }
181→
182→        if ($no === 0) {
183→            info("[lbl][0422-AI日报邮件][AiEmailJob] sfuser={$sfuserId} 无有效日报内容，跳过");
184→            return;
185→        }
186→
187→        $subject = EncryptService::app()->markEncrString("【{$reportDate}】智能日报");
188→
189→        $params = [
190→            'decrypt_config' => [
191→                'obj' => '$this',
192→                'decrypt_columns' => [],
193→                'partly_decrypt_columns' => ['content', 'subject'],
194→            ],
195→            'receivers' => [[
196→                'type' => 'token',
197→                'tokens' => [$sfuserToken],
198→                'filter' => 'emails',
199→                'filter_map' => ['emails' => $toEmails],
200→            ]],
201→            'content' => $content,
202→            'subject' => $subject,
203→            'ai_analysis_config' => [
204→                'system_prompt' => self::SYSTEM_PROMPT,
205→                'compress' => true,
206→            ],
207→        ];
208→
209→        info("[lbl][0422-AI日报邮件][AiEmailJob] sfuser={$sfuserId} 发送邮件", [
210→            'report_count' => $no,
211→            'subordinate_count' => count($subordinateIds),
212→            'date' => $reportDate,
213→            'to_emails' => $toEmails,
214→        ]);
215→
216→        $t0 = microtime(true);
217→        $result = CoreApiLib::sendRequest('master-api/mail/send-decr', $params);
218→
219→        info("[lbl][0422-AI日报邮件][AiEmailJob] sfuser={$sfuserId} 发送完成", [
220→            'elapsed' => round(microtime(true) - $t0, 2),
221→            'result_code' => $result['error_code'] ?? null,
222→            'result_msg' => $result['error_msg'] ?? null,
223→        ]);
224→    }
225→}
