 46→    public function handle(): bool
 47→    {
 48→        // 工作日判断
 49→        $today = now()->toDateString();
 50→        $todayCalendar = ShiftCalendar::where('full_date', $today)->first();
 51→        if (!$todayCalendar || $todayCalendar->is_weekend || $todayCalendar->is_holiday) {
 52→            info('[lbl][0422-AI日报邮件][AiEmailJob] 非工作日，跳过');
 53→            return true;
 54→        }
 55→
 56→        // 白名单直接主管
 57→        $managerIds = $this->getWhitelistManagerIds();
 58→        if (empty($managerIds)) {
 59→            info('[lbl][0422-AI日报邮件][AiEmailJob] 白名单为空，跳过');
 60→            return true;
 61→        }
 62→
 63→        // 额外收件人邮箱（每封邮件都抄送）
 64→        $extraEmails = $this->getExtraEmails();
 65→
 66→        info('[lbl][0422-AI日报邮件][AiEmailJob] 开始处理', [
 67→            'date' => $today,
 68→            'manager_count' => count($managerIds),
 69→            'manager_ids' => $managerIds,
 70→            'extra_emails' => $extraEmails,
 71→        ]);
 72→
 73→        // 获取上个工作日
 74→        $lastWorkday = ShiftCalendar::where('is_weekend', 0)
 75→            ->where('is_holiday', 0)
 76→            ->where('full_date', '<', $today)
 77→            ->orderByDesc('full_date')
 78→            ->value('full_date');
 79→
 80→        if (!$lastWorkday) {
 81→            info('[lbl][0422-AI日报邮件][AiEmailJob] 找不到上个工作日，跳过');
 82→            return true;
 83→        }
 84→
 85→        $processedCount = 0;
 86→        $totalManagers = count($managerIds);
 87→
 88→        foreach ($managerIds as $sfuserId) {
 89→            try {
 90→                $this->processManager($sfuserId, $lastWorkday, $extraEmails);
 91→                ++$processedCount;
 92→            } catch (\Throwable $e) {
 93→                info("[lbl][0422-AI日报邮件][AiEmailJob] sfuser={$sfuserId} 处理失败: {$e->getMessage()}", [
 94→                    'trace' => mb_substr($e->getTraceAsString(), 0, 500),
 95→                ]);
 96→            }
 97→
 98→            // 间隔 65 秒，避免打满 Vertex AI TPM 配额
 99→            if ($processedCount < $totalManagers) {
100→                info("[lbl][0422-AI日报邮件][AiEmailJob] 等待 65s 处理下一个主管");
101→                sleep(65);
102→            }
103→        }
104→
105→        info('[lbl][0422-AI日报邮件][AiEmailJob] 全部完成', [
106→            'processed' => $processedCount,
107→            'total' => $totalManagers,
108→        ]);
109→
110→        return true;
111→    }
112→
113→    /**
114→     * 获取白名单直接主管 ID 列表.
115→     */
116→    private function getWhitelistManagerIds(): array
117→    {
118→        $setting = OaSetting::where('type', 'daily_report_ai')->select('ids', 'is_on')->first();
119→
120→        return ($setting && $setting->is_on) ? array_values(array_unique($setting->ids ?? [])) : [];
121→    }
122→
123→    /**
124→     * 获取固定额外收件人的邮箱列表（每封邮件都抄送）.
125→     */
126→    private function getExtraEmails(): array
127→    {
128→        $emails = [];
129→        foreach (self::EXTRA_RECIPIENT_IDS as $extraId) {
130→            $mc = MailConfig::where('type', "daily_report_{$extraId}")->first();
131→            $toEmails = $mc ? Arr::get($mc->config, 'to_email', []) : [];
132→            if (!empty($toEmails)) {
133→                $emails = array_merge($emails, $toEmails);
134→            }
135→        }
136→
137→        return array_values(array_unique($emails));
138→    }
139→
140→    /**
141→     * 处理单个直接主管：查直属下属日报 → 组装邮件 → 发送给主管 + 额外收件人.
142→     */
143→    private function processManager(int $sfuserId, string $reportDate, array $extraEmails): void
144→    {
145→        // 读取邮箱配置
146→        $mc = MailConfig::where('type', "daily_report_{$sfuserId}")->first();
147→        if (!$mc || empty(Arr::get($mc->config, 'to_email'))) {
148→            info("[lbl][0422-AI日报邮件][AiEmailJob] sfuser={$sfuserId} 无邮箱配置，跳过");
149→            return;
150→        }
151→
152→        // 主管自己的邮箱 + 额外收件人邮箱合并去重
153→        $managerEmails = Arr::get($mc->config, 'to_email');
154→        $toEmails = array_values(array_unique(array_merge($managerEmails, $extraEmails)));
155→        $sfuserToken = Arr::get($mc->config, 'sfuser_authorized_token', '');
156→        if (!$sfuserToken) {
157→            info("[lbl][0422-AI日报邮件][AiEmailJob] sfuser={$sfuserId} 无 token，跳过");
158→            return;
159→        }
160→
161→        // 查询直属下属（direct_supervisor_id = 当前收件人）
162→        $subordinateIds = Sfuser::where('direct_supervisor_id', $sfuserId)
163→            ->where('status', 1)
164→            ->pluck('id')
165→            ->toArray();
166→
167→        if (empty($subordinateIds)) {
168→            info("[lbl][0422-AI日报邮件][AiEmailJob] sfuser={$sfuserId} 无直属下属，跳过");
169→            return;
170→        }
171→
172→        // 拉取日报数据
173→        $dailyService = app(DailyReportService::class);
174→        $data = $dailyService->getOthersDailyReportListEnable(
175→            $reportDate,
176→            $reportDate,
177→            $sfuserId,
178→            $subordinateIds,
179→            10000
180→        );
181→
182→        if (empty($data['reports']['report_list'])) {
183→            info("[lbl][0422-AI日报邮件][AiEmailJob] sfuser={$sfuserId} 日期={$reportDate} 无日报数据，跳过");
184→            return;
185→        }
186→
187→        $reportList = $data['reports']['report_list'];
188→
189→        // 组装邮件内容
190→        $content = '';
191→        $no = 0;
192→        foreach ($reportList as $report) {
193→            $nickname = $report['data']['nickname'] ?? '';
194→            if (empty($nickname)) {
195→                continue;
196→            }
197→            $nickname = EncryptService::app()->markEncrString(e($nickname));
198→            $reportContent = EncryptService::app()->markEncrString($report['content']);
199→            ++$no;
200→            $content .= '<p><b>'.$no.'、 '.$nickname.'</b></p>';
201→            $content .= '<div style="border:1px solid #eee;padding:8px;margin-bottom:12px;">'.$reportContent.'</div>';
202→        }
203→
204→        if ($no === 0) {
205→            info("[lbl][0422-AI日报邮件][AiEmailJob] sfuser={$sfuserId} 无有效日报内容，跳过");
206→            return;
207→        }
208→
209→        $subject = EncryptService::app()->markEncrString("【{$reportDate}】智能日报");
210→
211→        $params = [
212→            'decrypt_config' => [
213→                'obj' => '$this',
214→                'decrypt_columns' => [],
215→                'partly_decrypt_columns' => ['content', 'subject'],
216→            ],
217→            'receivers' => [[
218→                'type' => 'token',
219→                'tokens' => [$sfuserToken],
220→                'filter' => 'emails',
221→                'filter_map' => ['emails' => $toEmails],
222→            ]],
223→            'content' => $content,
224→            'subject' => $subject,
225→            'ai_analysis_config' => [
226→                'system_prompt' => self::SYSTEM_PROMPT,
227→                'compress' => true,
228→            ],
229→        ];
230→
231→        info("[lbl][0422-AI日报邮件][AiEmailJob] sfuser={$sfuserId} 发送邮件", [
232→            'report_count' => $no,
233→            'subordinate_count' => count($subordinateIds),
234→            'date' => $reportDate,
235→            'to_emails' => $toEmails,
236→        ]);
237→
238→        $t0 = microtime(true);
239→        $result = CoreApiLib::sendRequest('master-api/mail/send-decr', $params);
240→
241→        info("[lbl][0422-AI日报邮件][AiEmailJob] sfuser={$sfuserId} 发送完成", [
242→            'elapsed' => round(microtime(true) - $t0, 2),
243→            'result_code' => $result['error_code'] ?? null,
244→            'result_msg' => $result['error_msg'] ?? null,
245→        ]);
246→    }
247→}
