348→    async handleConfirm() {
349→        // 先全量校验（自定义分组 + 我的关注）
350→        const editableRows = [
351→            ...this.customTableData,
352→            ...this.defaultGroupsTableData.filter((r: any) => r.id === 'focus_users'),
353→        ]
354→        for (const row of editableRows) {
355→            this.validateRow(row)
356→            if (row.inputError) {
357→                this.$message.warning('请修正错误后再确认')
358→                return
359→            }
360→        }
361→
362→        // 跨组重复检查
363→        const seen = new Map<string, string>() // name -> groupName
364→        for (const row of editableRows) {
365→            const names = row.inputValue.split(/[,，]/).map((n: string) => n.trim()).filter((n: string) => n)
366→            for (const name of names) {
367→                if (seen.has(name)) {
368→                    this.$message.warning(`"${name}" 已在分组「${seen.get(name)}」中，同一成员不能重复出现在多个分组`)
369→                    return
370→                }
371→                seen.set(name, row.group_name)
372→            }
373→        }
374→
375→        // diff 并调接口：自定义分组
376→        for (const row of this.customTableData) {
377→            const newMembers = row.inputValue.split(/[,，]/).map((n: string) => n.trim()).filter((n: string) => n)
378→            const oldMembers: string[] = row.members || []
379→            const toAdd = newMembers.filter((m: string) => !oldMembers.includes(m))
380→            const toRemove = oldMembers.filter((m: string) => !newMembers.includes(m))
381→            for (const nickname of toAdd) {
382→                await dailyReportApis.addGroupUser({ group_id: row.id, nickname, sys_site: this.sysSite })
383→            }
384→            for (const nickname of toRemove) {
385→                await dailyReportApis.deleteGroupUser({ group_id: row.id, nickname, sys_site: this.sysSite })
386→            }
387→        }
388→
389→        // diff 并调接口：我的关注
390→        const focusRow = this.defaultGroupsTableData.find((r: any) => r.id === 'focus_users')
391→        if (focusRow) {
392→            const newMembers = focusRow.inputValue.split(/[,，]/).map((n: string) => n.trim()).filter((n: string) => n)
393→            const oldMembers: string[] = focusRow.members || []
394→            const toAdd = newMembers.filter((m: string) => !oldMembers.includes(m))
395→            const toRemove = oldMembers.filter((m: string) => !newMembers.includes(m))
396→            for (const nickname of toAdd) {
397→                await dailyReportApis.setFocusUserAPI({ type: 'add', nickname, sys_site: this.sysSite })
398→            }
399→            for (const nickname of toRemove) {
400→                await dailyReportApis.setFocusUserAPI({ type: 'delete', nickname, sys_site: this.sysSite })
401→            }
402→        }
403→
404→        this.visible = false
405→        this.$emit('confirm')
406→    }
407→}
