async saveGroupOrder(showTip: boolean = true) {
    const sortGroups = this.customTableData.map((item: any) => ({
        userID: item.group_name,
        nickname: item.group_name,
        releaseID: item.releaseID || '',
    }))
    const params = {
        sortGroups,
        sys_site: this.sysSite,
    }
    const res = await dailyReportApis.editGroup(params)
    if (res && showTip) {
        this.$message.success(this.$t('groupSettings.successSortOrder') as string)
    }
}

validateRow(row: any) {
    const names = row.inputValue.split(/[,，]/).map((n: string) => n.trim()).filter((n: string) => n)
    const invalid = names.filter((n: string) => !this.allValidNames.includes(n))
    row.inputError = invalid.length > 0 ? `花名 ${invalid.join('、')} 不存在` : ''

