154→    /**
155→     * 处理单个白名单用户：查该用户能看到的所有日报 → 组装邮件 → 用 EXTRA_RECIPIENT token 解密，发送给额外收件人 + 该用户.
156→     *
157→     * @param array{sfuser_id: int, email: string} $user
158→     * @param array{emails: string[], token: string} $extraConfig
159→     */
160→    private function processUser(array $user, string $reportDate, array $extraConfig): void
161→    {
162→        $sfuserId = $user['sfuser_id'];
163→        $userEmail = $user['email'];
164→        $sfuserToken = $extraConfig['token'];
165→
166→        // 收件人 = 额外收件人邮箱 + 当前白名单用户邮箱
167→        $toEmails = array_values(array_unique(array_merge($extraConfig['emails'], [$userEmail])));
168→
169→        // 获取该用户能看到的所有人（直属下属、部门下属、抄送、关注等）
170→        $dailyService = app(DailyReportService::class);
171→        $subordinates = $dailyService->getSubordinates($sfuserId);
172→        $focusUserIds = array_unique(array_merge(
173→            $subordinates['direct_subordinates'] ?? [],
174→            $subordinates['depart_subordinates'] ?? [],
175→            $subordinates['other_subordinates'] ?? [],
176→            $subordinates['focus_users'] ?? []
