private function getExtraRecipientConfig(): array
{
    $emails = [];
    $token = '';
    $recipientIds = AppEnv::isProduction() ? self::EXTRA_RECIPIENT_IDS_PROD : self::EXTRA_RECIPIENT_IDS_STAGING;
    foreach ($recipientIds as $extraId) {
        $mc = MailConfig::where('type', "daily_report_{$extraId}")->first();
        if (!$mc) {
            continue;
        }
        $toEmails = Arr::get($mc->config, 'to_email', []);
        if (!empty($toEmails)) {
            $emails = array_merge($emails, $toEmails);
        }
        // 取第一个有效 token 作为解密凭据
        if (empty($token)) {
            $token = Arr::get($mc->config, 'sfuser_authorized_token', '');
        }
    }

    return ['emails' => array_values(array_unique($emails)), 'token' => $token];
}

/**
 * 处理单个白名单用户：查该用户能看到的所有日报 → 组装邮件 → 用 EXTRA_RECIPIENT token 解密，发送给额外收件人 + 该用户.
 *
 * @param array{sfuser_id: int, email: string} $user
 * @param array{emails: string[], token: string} $extraConfig
 */
private function processUser(array $user, string $reportDate, array $extraConfig): void
{
    $sfuserId = $user['sfuser_id'];
    $userEmail = $user['email'];
    $sfuserToken = $extraConfig['token'];

    // 收件人 = 额外收件人邮箱 + 当前白名单用户邮箱
    $toEmails = array_values(array_unique(array_merge($extraConfig['emails'], [$userEmail])));

    // 获取该用户能看到的所有人（直属下属、部门下属、抄送、关注等）
    $dailyService = app(DailyReportService::class);
    $subordinates = $dailyService->getSubordinates($sfuserId);
    $focusUserIds = array_unique(array_merge(
        $subordinates['direct_subordinates'] ?? [],
        $subordinates['depart_subordinates'] ?? [],
        $subordinates['other_subordinates'] ?? [],
        $subordinates['focus_users'] ?? []
    ));

    if (empty($focusUserIds)) {
        info("[lbl][0422-AI日报邮件][AiEmailJob] sfuser={$sfuserId} 无可查看用户，跳过");
        return;
    }

    // 拉取日报数据
    $data = $dailyService->getOthersDailyReportListEnable(
        $reportDate,
        $reportDate,
        $sfuserId,
        array_values($focusUserIds),
        10000
    );

    if (empty($data['reports']['report_list'])) {
        info("[lbl][0422-AI日报邮件][AiEmailJob] sfuser={$sfuserId} 日期={$reportDate} 无日报数据，跳过");
        return;
    }

    $reportList = $data['reports']['report_list'];

    // 组装邮件内容
    $content = '';
    $no = 0;
    foreach ($reportList as $report) {
        $nickname = $report['data']['nickname'] ?? '';
        if (empty($nickname)) {
            continue;
        }
        $nickname = EncryptService::app()->markEncrString(e($nickname));
        $reportContent = EncryptService::app()->markEncrString($report['content']);

