                                authorize_config: {
                                    res_type: 'sfuser',
                                    sfusers: [],
                                    emails: allEmails,
                                    items: 'all',
                                    operations: ['send_email'],
                                    expire_time: 4294967295,
                                },
                            })
                                .then(r => resolve(r))
                                .catch(e => {
                                    console.error('editOaSettingDataAPI error', e)
