export const editOaSettingDataAPI = (param: APCDataT) =>
    new Promise((resolve, reject) => {
        const nicknames = param.ASSPerson.map(o => o.label)
        getUserByNickName([...param.ASSPerson.map(o => o.label), ...param.group.map(o => o.nickName)])
            .then(userMap => {
                const sfuser_ids = param.ASSPerson.map(o => userMap.getByName(o.label)?.sfUserId)
                // 花名找不到对应用户时仅警告，不阻断保存
                const notFoundNames = param.ASSPerson.filter(o => !userMap.getByName(o.label)?.sfUserId).map(o => o.label)
                if (notFoundNames.length > 0) {
                    console.warn('[OaSetting] 以下花名未找到对应员工，已跳过：', notFoundNames)
                }
                // 过滤掉找不到用户的花名，只保存有效的
                const validNicknames = param.ASSPerson.filter(o => userMap.getByName(o.label)?.sfUserId).map(o => o.label)
                const validSfuserIds = sfuser_ids.filter(Boolean)

                // daily_report_ai：通过 staff 接口查白名单用户解密邮箱 + EXTRA_RECIPIENT 邮箱，生成 token
                if (param.id === 'daily_report_ai') {
                    Promise.all([
                        axios2(`${ajaxUrl.WebAPI}staff`, 'post', {
                            intact_columns: ['nicknames'],
                            hash_filter: {
                                obj: '$this',
                                columns: ['nicknames'],
                            },
                            nicknames: validNicknames,
                            per_page: validNicknames.length || 1,
                            decrypt_config: {
                                obj: 'sfusers.*',
                                decrypt_columns: ['nickname', 'email'],
                            },
                        }),
                        getEmailConfigAPI(`daily_report_${AI_EMAIL_EXTRA_RECIPIENT_ID}`),
                    ])
                        .then(([staffRes, emailConfig]: [any, any]) => {
                            // 从 staff 接口响应中提取 sfuser_id → email 映射，查不到的用兜底 map 补
                            const staffList: any[] = staffRes?.sfusers || []
                            const staffEmailMap = new Map(staffList.filter(s => s.id && s.email).map(s => [s.id, s.email]))
                            const whitelistEmailConfigs = validSfuserIds.map((sfuserId, idx) => {
                                const nickname = validNicknames[idx] || ''
                                const email = staffEmailMap.get(sfuserId) || AI_EMAIL_NICKNAME_FALLBACK[nickname] || ''
                                if (!email) {
                                    console.warn(`[OaSetting] 白名单用户 ${nickname}(${sfuserId}) 无邮箱且无兜底配置`)
                                }
                                return {sfuser_id: sfuserId, email}
                            }).filter(o => !!o.email)

                            const extraEmails: string[] = emailConfig?.data?.[0]?.email || []
                            const whitelistEmails = whitelistEmailConfigs.map(o => o.email)
                            const allEmails = [...new Set([...extraEmails, ...whitelistEmails])]

                            console.info('[lbl][0422-AI日报邮件][OaSetting][UPDATE] 保存白名单配置', {
                                sfuser_ids: validSfuserIds,
                                whitelistCount: whitelistEmailConfigs.length,
                                allEmailCount: allEmails.length,
                            })
                            axios2(`${ajaxUrl.WebAPI}hr-approval/edit-oa-setting`, 'post', {
                                intact_columns: ['type', 'nicknames_plaintext', 'special_config', 'sfuser_ids', 'ai_email_all_emails'],
                                type: param.id,
                                sfuser_ids: validSfuserIds,
                                nicknames_plaintext: validNicknames,
                                // special_config 存白名单用户的 sfuser_id + 明文邮箱
                                special_config: whitelistEmailConfigs,
                                // 所有邮箱（EXTRA_RECIPIENT + 白名单），用于 authorize_config 生成 token
                                ai_email_all_emails: allEmails,
                                // authorize_config 让 oa-core 生成包含所有邮箱的 token
                                authorize_config: {
                                    res_type: 'sfuser',
                                    sfusers: [],
                                    emails: allEmails,
                                    items: 'all',
                                    operations: ['send_email'],
                                    expire_time: 4294967295,
                                },
                            })
                                .then(r => resolve(r))
                                .catch(e => {
                                    console.error('editOaSettingDataAPI error', e)
                                    reject(e.error_msg || <string>i18n.t('serverException'))
                                })
                        })
                        .catch(e => {
                            console.error('editOaSettingDataAPI daily_report_ai error', e)
                            reject(e)
                        })
                    return
                }

                // 非 daily_report_ai 的原有逻辑
                axios2(`${ajaxUrl.WebAPI}hr-approval/edit-oa-setting`, 'post', {
                    intact_columns: ['type', 'nicknames_plaintext', 'special_config', 'sfuser_ids'],
                    type: param.id,
                    sfuser_ids: validSfuserIds,
                    nicknames_plaintext: validNicknames,
                    special_config: param.group.map(o => ({
                        sfuser_ids: [userMap.getByName(o.nickName)?.sfUserId],
                        nicknames_plaintext: [o.nickName],
                        department_ids: o.deptList.map(o => o.value),
                    })),
                })
                    .then(r => {
                        if (isOtherType(param.id)) {
                            sfuser_ids && sfuser_ids.forEach(sfuser_id => {
                                forceUpdateStaffSfUserAllResAttrAPI(sfuser_id, userMap.getBySfUserId(sfuser_id).nickName).then(r => r)
                            })
                        }
                        resolve(r)
                    })
                    .catch(e => {
                        console.error('editOaSettingDataAPI error', e)
                        reject(e.error_msg || <string>i18n.t('serverException'))
                    })
            })
            .catch(e => {
                reject(e)
            })
    })

