export type DeptDataT = {
    id: number
    name: string
    sscName: string
    creator: string
    createTime: string
    updateTime: string
    status: boolean
}

export const defaultDeptData: DeptDataT = {
    id: 0,
    name: '',
    status: true,
    sscName: '',
    updateTime: '',
    creator: '',
    createTime: '',
}

export const getDeptListAPI = (): Promise<DeptDataT[]> =>
    new Promise((resolve, reject) => {
        axios2(`${ajaxUrl.WebAPI}configuration-management`, 'post', {}, 'auto')
            .then(r => {
                resolve(
                    r.departments.map((o): DeptDataT => {
                        return {
                            id: o.department_id,
                            name: o.department_name,
                            createTime: dayjs(toNumber(o.created_at) * 1000).format('YYYY-MM-DD hh:mm:ss'),
                            creator: o.creator_id,
                            sscName: o.ssc_id,
                            updateTime: dayjs(toNumber(o.updated_at) * 1000).format('YYYY-MM-DD hh:mm:ss'),
                            status: !!o.is_on,
                        }
                    })
                )
            })
            .catch(e => {
                console.error(e)
                reject(e)
            })
    })

export const addDeptAPI = (param: DeptDataT) =>
    axios2(
        `${ajaxUrl.WebAPI}jobs/add-department`,
        'post',
        {
            department_name: param.name,
            ssc_id: param.sscName,
        },
