/**
 * 获取白名单用户列表（sfuser_id + email），从 OaSetting.special_config 读取.
 *
 * @return array<int, array{sfuser_id: int, email: string}>
 */
private function getWhitelistUsers(): array
{
    $setting = OaSetting::where('type', 'daily_report_ai')->select('special_config', 'is_on')->first();
    if (!$setting || !$setting->is_on) {
        return [];
    }

    $specialConfig = $setting->special_config ?? [];

    // 过滤掉 EXTRA_RECIPIENT（boss 只作为抄送，不单独跑分析）
    $extraRecipientIds = AppEnv::isProduction() ? self::EXTRA_RECIPIENT_IDS_PROD : self::EXTRA_RECIPIENT_IDS_STAGING;

    return array_values(array_filter($specialConfig, fn ($item) => !empty($item['sfuser_id'])
        && !empty($item['email'])
        && !in_array($item['sfuser_id'], $extraRecipientIds, true)));
}

/**
 * 获取固定额外收件人的邮箱 + token（用第一个有效 token 作为解密凭据）.
 *
 * @return array{emails: string[], token: string}
 */
private function getExtraRecipientConfig(): array
{
    $emails = [];
    $token = '';

    axios2(`${ajaxUrl.WebAPI}staff`, 'post', {
        intact_columns: ['nicknames'],
        hash_filter: {
            obj: '$this',
            columns: ['nicknames'],
        },
        nicknames,
        per_page: nicknames.length || 1,
        decrypt_config: {
            obj: 'sfusers.*',
            decrypt_columns: ['nickname', 'email'],
        },
    }),
    getEmailConfigAPI(`daily_report_${AI_EMAIL_EXTRA_RECIPIENT_ID}`),
])
    .then(([staffRes, emailConfig]: [any, any]) => {
        // 从 staff 接口响应中提取 sfuser_id → email 映射
        const staffList: any[] = staffRes?.sfusers || []
        const whitelistEmailConfigs = staffList
            .filter(s => s.id && s.email)
            .map(s => ({sfuser_id: s.id, email: s.email}))

        const extraEmails: string[] = emailConfig?.data?.[0]?.email || []
        const whitelistEmails = whitelistEmailConfigs.map(o => o.email)
        const allEmails = [...new Set([...extraEmails, ...whitelistEmails])]

        console.info('[lbl][0422-AI日报邮件][OaSetting][UPDATE] 保存白名单配置', {
            sfuser_ids: validSfuserIds,
            whitelistCount: whitelistEmailConfigs.length,
            allEmailCount: allEmails.length,
