/**
 * 获取白名单用户列表（sfuser_id + email），从 OaSetting.special_config 读取.
 *
 * @return array<int, array{sfuser_id: int, email: string}>
 */
private function getWhitelistUsers(): array
{
    $setting = OaSetting::where('type', 'daily_report_ai')->select('special_config', 'is_on')->first();
    if (!$setting || !$setting->is_on) {
        return [];
    }

    $specialConfig = $setting->special_config ?? [];

    // 过滤掉 EXTRA_RECIPIENT（boss 只作为抄送，不单独跑分析）
    $extraRecipientIds = AppEnv::isProduction() ? self::EXTRA_RECIPIENT_IDS_PROD : self::EXTRA_RECIPIENT_IDS_STAGING;

    return array_values(array_filter($specialConfig, fn ($item) => !empty($item['sfuser_id'])
        && !empty($item['email'])
        && !in_array($item['sfuser_id'], $extraRecipientIds, true)));
}

